update paper
name = #{name}, total_score = #{totalScore}, duration = #{duration}, single_count = #{singleCount}, multi_count = #{multiCount}, judge_count = #{judgeCount}, fill_count = #{fillCount}, essay_count = #{essayCount}, single_score = #{singleScore}, multi_score = #{multiScore}, judge_score = #{judgeScore}, fill_score = #{fillScore}, essay_score = #{essayScore}, description = #{description}, status = #{status},
where id = #{id}
